connectionString = mssparkutils.credentials.getSecret(
    "synapseFin-kv-dev",  
    "ehConnectionString",
    "ls_keyvault"
)

ehConf = {
  'eventhubs.connectionString': sc._jvm.org.apache.spark.eventhubs.EventHubsUtils.encrypt(connectionString),
  'eventhubs.startingPosition': json.dumps({
      "offset": "-1",
      "seqNo": -1,
      "enqueuedTime": None,
      "isInclusive": True
  })

fx_rates = []

start_date = datetime(2023,1,1)
end_date = datetime(2025,12,31)

currencies = ["USD","INR","AED","CNY"]

current_date = start_date

while current_date <= end_date:

    for currency in currencies:

        if currency == "USD":
            rate = 1.0
        elif currency == "INR":
            rate = float(f"{random.uniform(70, 85):.4f}")
        elif currency == "AED":
            rate = float(f"{random.uniform(3.5, 3.8):.4f}")
        elif currency == "CNY":
            rate = float(f"{random.uniform(6.0, 7.5):.4f}")

        fx_rates.append((
            currency,
            rate,
            current_date.date(),
            datetime.now()
        ))

    current_date += timedelta(days=1)
